import{_ as e,c as r,o,ak as s}from"./chunks/framework.CmzJUe0_.js";const m="/assets/mobaxterm_20250906164822491.DSMElCR1.png",p="/assets/mobaxterm_20250906170008863.CxEdjPOO.png",i="/assets/mobaxterm_20250906170340402.CiKx0PHY.png",n="/assets/mobaxterm_20250906171641180.C55UecZU.png",l="/assets/mobaxterm_20250906172059305.DmaFfnzV.png",a="/assets/mobaxterm_20250906172404803.BAGjIPVG.png",M=JSON.parse('{"title":"MobaXterm终端工具笔记","description":"","frontmatter":{"title":"MobaXterm终端工具笔记","date":"2025-09-06T00:00:00.000Z","lastUpdated":"2025-09-06T00:00:00.000Z","categories":["随笔"]},"headers":[],"relativePath":"blogs/随笔/MobaXterm终端工具笔记.md","filePath":"blogs/随笔/MobaXterm终端工具笔记.md"}'),b={name:"blogs/随笔/MobaXterm终端工具笔记.md"};function _(c,t,g,d,S,h){return o(),r("div",null,t[0]||(t[0]=[s('<p>[toc]</p><h1 id="mobaxterm终端工具笔记" tabindex="-1">MobaXterm终端工具笔记 <a class="header-anchor" href="#mobaxterm终端工具笔记" aria-label="Permalink to &quot;MobaXterm终端工具笔记&quot;">​</a></h1><p><img src="'+m+'" alt="blog_20250906164822491.png"></p><p>MobaXterm官网：<a href="https://mobaxterm.mobatek.net/" target="_blank" rel="noreferrer">https://mobaxterm.mobatek.net/</a></p><p>MobaXterm 是一款功能强大的远程访问终端工具，它将xshell和xftp的优点结合起来，适用于IT从业者和Linux系统管理员。</p><p>MobaXterm 支持SSH协议，提供颜色丰富的代码高亮显示，界面设计友好，易用性高。内置FTP客户端功能，提供稳定快速的文件传输服务。此外，MobaXterm还支持多种协议和安全认证机制，是远程终端操作和文件管理的理想选择。</p><p>MobaXterm主要功能如下所示</p><ul><li>支持各种连接 SSH，X11，RDP，VNC，FTP，MOSH</li><li>支持 Unix 命令(bash，ls，cat，sed，grep，awk，rsync，…)</li><li>连接 SSH 终端后支持 SFTP 传输文件</li><li>各种丰富的插件(git/dig/aria2…)</li><li>可运行 Windows 或软件</li></ul><h2 id="mobaxterm-下载并安装" tabindex="-1">MobaXterm 下载并安装 <a class="header-anchor" href="#mobaxterm-下载并安装" aria-label="Permalink to &quot;MobaXterm 下载并安装&quot;">​</a></h2><p>访问MobaXterm官网，下载MobaXterm安装包。</p><p>MobaXterm 分免费开源版和收费专业版。免费开源版又分绿色免安装版(解压即用)和安装版(需要一步步安装)。</p><p>可以下载免费的免安装版本或安装版本。 <img src="'+p+'" alt="blog_20250906170008863.png"></p><p>安装完之后，软件运行的界面如下所示 <img src="'+i+'" alt="blog_20250906170340402.png"></p><h2 id="使用ssh终端" tabindex="-1">使用SSH终端 <a class="header-anchor" href="#使用ssh终端" aria-label="Permalink to &quot;使用SSH终端&quot;">​</a></h2><p>点击菜单栏 「sessions」 –&gt; 「new session」，在「session setting」对话框中填写SSH连接信息,填写完成后点击「OK」按钮。</p><p><img src="'+n+'" alt="mobaxterm_20250906171641180.png"></p><p>第一次连接SSH终端时，会弹出一个对话框，要求设置master password，即打开会话的密码。</p><p><img src="'+l+'" alt="mobaxterm_20250906172059305.png"></p><p>输入服务器的密码，成功登录服务器后，即可在MobaXterm中使用SSH终端。界面如下所示。</p><p><img src="'+a+'" alt="mobaxterm_20250906172404803.png"></p><p>界面主要分两块，左边的是服务器的文件，右边是服务器的终端。</p><h2 id="使用sftp服务操控文件" tabindex="-1">使用SFTP服务操控文件 <a class="header-anchor" href="#使用sftp服务操控文件" aria-label="Permalink to &quot;使用SFTP服务操控文件&quot;">​</a></h2><p>当我们使用SSH服务远程登录服务器后，会默认开启一个SFTP窗口，我们可以在SFTP窗口进行上传、下载文件。也可以执行创建文件夹、删除等操作。</p><p><img src="'+a+'" alt="mobaxterm_20250906172404803.png"></p>',24)]))}const X=e(b,[["render",_]]);export{M as __pageData,X as default};
